import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';
import App from './App';
import * as serviceWorker from './serviceWorker';

let posts = [
    { id: 1, post: "fuck u", likesCount: 5 },
    { id: 1, post: "good luck", likesCount: 23 },
    { id: 1, post: "nice try", likesCount: 13 },
    { id: 1, post: "maybe", likesCount: 76 },
    { id: 1, post: "real talk", likesCount: 29 }
]

let dialogs = [
    { id: 1, name: "Misha" },
    { id: 2, name: "Vika Nine 22" },
    { id: 3, name: "Sinfozatron" },
    { id: 4, name: "Dasha Nine 2" }
]

let messages = [
    { id: 1, message: "Привет" },
    { id: 2, message: "Игорек,как дела?" },
    { id: 3, message: "В качалку гоним к 12.00" },
    { id: 4, message: "Молчишь-в жопе торчишь" }
]

ReactDOM.render( <
    React.StrictMode >
    <
    App posts = { posts }
    dialogs = { dialogs }
    messages = { messages }
    /> <
    /React.StrictMode>,
    document.getElementById('root')
);

// If you want your app to work offline and load faster, you can change
// unregister() to register() below. Note this comes with some pitfalls.
// Learn more about service workers: https://bit.ly/CRA-PWA
serviceWorker.unregister();
